{"metadata":{"kernelspec":{"language":"python","display_name":"Python 3","name":"python3"},"language_info":{"pygments_lexer":"ipython3","nbconvert_exporter":"python","version":"3.6.4","file_extension":".py","codemirror_mode":{"name":"ipython","version":3},"name":"python","mimetype":"text/x-python"},"kaggle":{"accelerator":"nvidiaTeslaT4","dataSources":[{"sourceId":14087291,"sourceType":"datasetVersion","datasetId":8969426}],"dockerImageVersionId":31193,"isInternetEnabled":true,"language":"python","sourceType":"script","isGpuEnabled":true}},"nbformat_minor":4,"nbformat":4,"cells":[{"cell_type":"code","source":"# %% [markdown]\n# # 🧠 DementiaNext FTD GAN - BALANCED VERSION (Kaggle)\n# \n# ## Optimized for: Kaggle GPU (16GB RAM + Tesla P100/T4)\n# \n# ### ⚖️ BALANCED = Best Quality + No Crash\n# \n# ---\n# \n# ## 📋 Training Configuration\n# \n# | Setting | Value |\n# |---------|-------|\n# | **Total Epochs** | 40 |\n# | **Checkpoint Save** | Epoch 20, 40 |\n# | **Evaluation** | Epoch 20, 40 |\n# | **Sample Images** | Epoch 20, 40 |\n# \n# ---\n# \n# **Quality Features ENABLED:**\n# - ✅ EMA (Exponential Moving Average) - smoother outputs\n# - ✅ Self-Attention - captures global brain structure\n# - ✅ Optimized architecture - full capacity\n# \n# **RAM-Safe Features:**\n# - ✅ Lightweight evaluation (32 samples only)\n# - ✅ RAM-efficient metrics (no O(N²) pairwise SSIM)\n# - ✅ Pre-loaded dataset (no NIfTI memory leaks)\n# - ✅ Aggressive garbage collection every 25 batches\n# - ✅ Memory cleanup after each epoch\n# \n# **Expected RAM:** 8-12 GB (safe for Kaggle's 16GB)\n# \n# ---\n# \n# ## 📋 Setup Instructions\n# \n# 1. **Upload your NIfTI dataset** to Kaggle Datasets\n# 2. **Add the dataset** to this notebook (right sidebar → Add Data)\n# 3. **Update `DATA_DIR`** in the Configuration cell below\n# 4. **Enable GPU** (Settings → Accelerator → GPU P100 or T4)\n# 5. **Run all cells!**\n# \n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:35:33.155216Z\",\"iopub.execute_input\":\"2025-12-10T09:35:33.156013Z\",\"iopub.status.idle\":\"2025-12-10T09:35:33.161477Z\",\"shell.execute_reply.started\":\"2025-12-10T09:35:33.155979Z\",\"shell.execute_reply\":\"2025-12-10T09:35:33.160936Z\"}}\n# =============================================================================\n# 📦 INSTALL DEPENDENCIES (if needed)\n# =============================================================================\n\nimport subprocess\nimport sys\n\ndef install_if_missing(package, import_name=None):\n    import_name = import_name or package\n    try:\n        __import__(import_name)\n    except ImportError:\n        print(f\"Installing {package}...\")\n        subprocess.check_call([sys.executable, '-m', 'pip', 'install', '-q', package])\n\n# Required packages\ninstall_if_missing('nibabel')\ninstall_if_missing('scikit-image', 'skimage')\ninstall_if_missing('tqdm')\ninstall_if_missing('psutil')\n\nprint(\"✅ All dependencies ready!\")\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:35:33.162811Z\",\"iopub.execute_input\":\"2025-12-10T09:35:33.163108Z\",\"iopub.status.idle\":\"2025-12-10T09:35:33.185953Z\",\"shell.execute_reply.started\":\"2025-12-10T09:35:33.163087Z\",\"shell.execute_reply\":\"2025-12-10T09:35:33.185409Z\"}}\n# =============================================================================\n# 📚 IMPORTS\n# =============================================================================\n\nimport os\nimport glob\nimport gc\nimport numpy as np\nimport torch\nimport torch.nn as nn\nimport torch.nn.functional as F\nfrom torch.utils.data import Dataset, DataLoader, TensorDataset\nfrom torch.optim import Adam\nimport torch.nn.utils.spectral_norm as spectral_norm\nimport nibabel as nib\nfrom skimage.transform import resize\nfrom skimage.metrics import structural_similarity as ssim\nfrom tqdm.auto import tqdm\nimport matplotlib.pyplot as plt\nfrom collections import deque\nimport zipfile\nimport copy\nimport warnings\nwarnings.filterwarnings('ignore')\n\n# Force garbage collection\ngc.enable()\n\n# Set random seeds\ntorch.manual_seed(42)\nnp.random.seed(42)\n\n# Check device\ndevice = torch.device('cuda' if torch.cuda.is_available() else 'cpu')\nprint(f\"🖥️ Device: {device}\")\nif torch.cuda.is_available():\n    print(f\"   GPU: {torch.cuda.get_device_name(0)}\")\n    print(f\"   VRAM: {torch.cuda.get_device_properties(0).total_memory / 1e9:.1f} GB\")\nelse:\n    print(\"⚠️ WARNING: GPU not detected! Training will be VERY slow.\")\n    print(\"   Go to Settings → Accelerator → Select GPU P100 or T4\")\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:35:33.186599Z\",\"iopub.execute_input\":\"2025-12-10T09:35:33.186853Z\",\"iopub.status.idle\":\"2025-12-10T09:35:33.212131Z\",\"shell.execute_reply.started\":\"2025-12-10T09:35:33.186831Z\",\"shell.execute_reply\":\"2025-12-10T09:35:33.211456Z\"}}\n# =============================================================================\n# ⚙️ KAGGLE CONFIGURATION\n# =============================================================================\n# ╔════════════════════════════════════════════════════════════════════════╗\n# ║                    🔧 UPDATE THIS SECTION!                             ║\n# ╚════════════════════════════════════════════════════════════════════════╝\n\nclass KaggleConfig:\n    \"\"\"\n    Kaggle-Optimized Configuration\n    \n    Kaggle Specs:\n    - GPU: Tesla P100 (16GB VRAM) or T4 (16GB VRAM)\n    - RAM: 16GB\n    - Runtime: 12 hours max (with GPU)\n    - Storage: 20GB output limit\n    \n    Training Plan:\n    - 40 epochs total\n    - Checkpoint & Evaluation at epoch 20 and 40 ONLY\n    - Minimized memory overhead\n    \"\"\"\n    \n    # ========================================================================\n    # 🔧 UPDATE THIS PATH TO YOUR KAGGLE DATASET!\n    # ========================================================================\n    # After adding your dataset, it will be at:\n    # /kaggle/input/YOUR-DATASET-NAME/...\n    # \n    # To find the exact path, run this in a cell:\n    # !ls -la /kaggle/input/\n    # !find /kaggle/input -name \"*.nii*\" | head -5\n    \n    DATA_DIR = '/kaggle/input/dataset123/ftd_gan/subjects'  # ← UPDATE THIS!\n    \n    # ========================================================================\n    # Project Settings\n    # ========================================================================\n    PROJECT_NAME = \"DementiaNext_Kaggle\"\n    TARGET_CLASS = \"FTD\"\n    \n    # Data\n    IMAGE_SIZE = 128\n    SLICE_AXIS = 'all'  # 'all', 'axial', 'sagittal', or 'coronal'\n    MIN_BRAIN_RATIO = 0.15\n    \n    # Model (FULL CAPACITY)\n    LATENT_DIM = 128\n    GEN_FEATURES = 64\n    DISC_FEATURES = 64\n    \n    # ========================================================================\n    # 🎯 TRAINING SETTINGS - 40 EPOCHS MAX\n    # ========================================================================\n    MAX_SAMPLES = 10000       # Reduced for stability\n    BATCH_SIZE = 24           # Slightly reduced for stability\n    EPOCHS = 40               # ← MAX 40 EPOCHS\n    \n    # WGAN-GP\n    LR_G = 0.0001\n    LR_D = 0.0004\n    LAMBDA_GP = 10.0\n    N_CRITIC = 5\n    \n    # Optimization\n    BETA1 = 0.0\n    BETA2 = 0.9\n    \n    # ========================================================================\n    # ⚖️ BALANCED SETTINGS (RAM-Safe)\n    # ========================================================================\n    USE_EMA = True              # ✅ ON - Smoother outputs\n    EMA_DECAY = 0.999\n    USE_SELF_ATTENTION = True   # ✅ ON - Global structure\n    USE_AMP = False             # OFF - Better stability\n    \n    # RAM-Safe Evaluation - Only 32 samples to minimize RAM\n    EVAL_SAMPLE_SIZE = 32       # Reduced from 64 for extra safety\n    COMPUTE_LIGHTWEIGHT_SSIM = True\n    COMPUTE_PIXEL_DIVERSITY = True\n    \n    # Gradient control\n    GRADIENT_CLIP_NORM = 1.0\n    \n    # ========================================================================\n    # 📊 GENERATION SETTINGS - Adjusted for Kaggle limits\n    # ========================================================================\n    # 128x128 grayscale PNG ≈ 5-10KB each\n    # 50,000 images ≈ 250-500MB (safe)\n    SYNTHETIC_TO_GENERATE = 50000\n    \n    # ========================================================================\n    # 📂 KAGGLE PATHS (Don't change these)\n    # ========================================================================\n    OUTPUT_DIR = '/kaggle/working/outputs'\n    CHECKPOINT_DIR = '/kaggle/working/checkpoints'\n    DEVICE = device\n    \n    # ========================================================================\n    # 🔄 CHECKPOINT & EVALUATION SCHEDULE\n    # ========================================================================\n    # Save checkpoint ONLY at epoch 20 and 40\n    SAVE_INTERVAL = 20        # ← Checkpoint at 20 and 40\n    # Evaluate ONLY at epoch 20 and 40  \n    EVAL_INTERVAL = 20        # ← Evaluate at 20 and 40\n\nconfig = KaggleConfig()\n\n# Create directories\nos.makedirs(config.OUTPUT_DIR, exist_ok=True)\nos.makedirs(config.CHECKPOINT_DIR, exist_ok=True)\n\nprint(\"\\n\" + \"=\" * 70)\nprint(\"⚖️ KAGGLE CONFIGURATION - 40 EPOCH RUN\")\nprint(\"=\" * 70)\nprint(f\"📂 DATA_DIR: {config.DATA_DIR}\")\nprint(f\"✅ EPOCHS: {config.EPOCHS} (max)\")\nprint(f\"✅ SAVE_INTERVAL: {config.SAVE_INTERVAL} (checkpoint at epoch 20, 40)\")\nprint(f\"✅ EVAL_INTERVAL: {config.EVAL_INTERVAL} (evaluate at epoch 20, 40)\")\nprint(f\"✅ BATCH_SIZE: {config.BATCH_SIZE}\")\nprint(f\"✅ MAX_SAMPLES: {config.MAX_SAMPLES:,}\")\nprint(f\"✅ EVAL_SAMPLE_SIZE: {config.EVAL_SAMPLE_SIZE} (RAM-safe)\")\nprint(f\"✅ USE_EMA: {config.USE_EMA}\")\nprint(f\"✅ USE_SELF_ATTENTION: {config.USE_SELF_ATTENTION}\")\nprint(\"=\" * 70)\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:35:33.259965Z\",\"iopub.execute_input\":\"2025-12-10T09:35:33.260338Z\",\"iopub.status.idle\":\"2025-12-10T09:35:35.215045Z\",\"shell.execute_reply.started\":\"2025-12-10T09:35:33.260321Z\",\"shell.execute_reply\":\"2025-12-10T09:35:35.214261Z\"}}\n# =============================================================================\n# 🔍 VERIFY DATA PATH\n# =============================================================================\n\nprint(\"🔍 Checking data path...\")\nprint()\n\n# List available input datasets\nprint(\"📂 Available datasets in /kaggle/input/:\")\nif os.path.exists('/kaggle/input'):\n    for item in os.listdir('/kaggle/input'):\n        print(f\"   - {item}\")\nelse:\n    print(\"   (Not running on Kaggle - using local paths)\")\n\nprint()\n\n# Check configured path\nif os.path.exists(config.DATA_DIR):\n    nifti_count = 0\n    for root, dirs, files in os.walk(config.DATA_DIR):\n        for f in files:\n            if f.endswith('.nii') or f.endswith('.nii.gz'):\n                nifti_count += 1\n    print(f\"✅ DATA_DIR exists: {config.DATA_DIR}\")\n    print(f\"   Found {nifti_count} NIfTI files\")\nelse:\n    print(f\"❌ DATA_DIR not found: {config.DATA_DIR}\")\n    print()\n    print(\"🔧 To fix this:\")\n    print(\"   1. Add your dataset using the 'Add Data' button (right sidebar)\")\n    print(\"   2. Run this to find your data:\")\n    print(\"      !find /kaggle/input -name '*.nii*' | head -10\")\n    print(\"   3. Update DATA_DIR in the Configuration cell above\")\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:35:35.216469Z\",\"iopub.execute_input\":\"2025-12-10T09:35:35.216665Z\",\"iopub.status.idle\":\"2025-12-10T09:35:35.222986Z\",\"shell.execute_reply.started\":\"2025-12-10T09:35:35.216649Z\",\"shell.execute_reply\":\"2025-12-10T09:35:35.222353Z\"}}\n# =============================================================================\n# 💾 RAM MONITORING\n# =============================================================================\n\nimport psutil\n\ndef print_memory_status():\n    \"\"\"Print current memory usage\"\"\"\n    ram = psutil.virtual_memory()\n    print(f\"💾 RAM: {ram.used/1e9:.1f} / {ram.total/1e9:.1f} GB ({ram.percent}%)\")\n    \n    if torch.cuda.is_available():\n        allocated = torch.cuda.memory_allocated() / 1e9\n        reserved = torch.cuda.memory_reserved() / 1e9\n        total = torch.cuda.get_device_properties(0).total_memory / 1e9\n        print(f\"🎮 VRAM: {allocated:.1f}GB allocated, {reserved:.1f}GB reserved / {total:.1f}GB total\")\n\nprint_memory_status()\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:35:35.223703Z\",\"iopub.execute_input\":\"2025-12-10T09:35:35.223940Z\",\"iopub.status.idle\":\"2025-12-10T09:35:35.244978Z\",\"shell.execute_reply.started\":\"2025-12-10T09:35:35.223925Z\",\"shell.execute_reply\":\"2025-12-10T09:35:35.244349Z\"}}\n# =============================================================================\n# 🛡️ RAM-SAFE DATASET\n# =============================================================================\n\nclass RAMSafeDataset(Dataset):\n    \"\"\"Pre-loads all slices into a single tensor (no memory leaks)\"\"\"\n    \n    def __init__(self, nifti_paths, config):\n        self.config = config\n        print(f\"\\n📂 Pre-loading slices into RAM...\")\n        \n        all_slices = []\n        axes = ['axial', 'sagittal', 'coronal'] if config.SLICE_AXIS == 'all' else [config.SLICE_AXIS]\n        \n        for path in tqdm(nifti_paths, desc=\"Loading NIfTI\"):\n            try:\n                volume = nib.load(path).get_fdata().astype(np.float32)\n                \n                for axis in axes:\n                    if len(all_slices) >= config.MAX_SAMPLES:\n                        break\n                    \n                    if axis == 'axial':\n                        n_slices = volume.shape[2]\n                        get_slice = lambda i: volume[:, :, i]\n                    elif axis == 'sagittal':\n                        n_slices = volume.shape[0]\n                        get_slice = lambda i: volume[i, :, :]\n                    else:\n                        n_slices = volume.shape[1]\n                        get_slice = lambda i: volume[:, i, :]\n                    \n                    for i in range(n_slices):\n                        if len(all_slices) >= config.MAX_SAMPLES:\n                            break\n                        \n                        slice_2d = get_slice(i)\n                        \n                        if np.sum(slice_2d > 0) / slice_2d.size < config.MIN_BRAIN_RATIO:\n                            continue\n                        \n                        brain_voxels = slice_2d[slice_2d > 0]\n                        if brain_voxels.size == 0:\n                            continue\n                        p2, p98 = np.percentile(brain_voxels, [2, 98])\n                        slice_2d = np.clip(slice_2d, p2, p98)\n                        if slice_2d.max() <= slice_2d.min():\n                            continue\n                        slice_2d = 2 * (slice_2d - slice_2d.min()) / (slice_2d.max() - slice_2d.min()) - 1\n                        \n                        slice_2d = resize(slice_2d, (config.IMAGE_SIZE, config.IMAGE_SIZE),\n                                         anti_aliasing=True, preserve_range=True).astype(np.float32)\n                        \n                        all_slices.append(slice_2d)\n                \n                del volume\n                gc.collect()\n                \n            except Exception as e:\n                continue\n        \n        print(f\"✅ Loaded {len(all_slices):,} slices\")\n        \n        self.data = torch.from_numpy(np.array(all_slices)).unsqueeze(1).float()\n        del all_slices\n        gc.collect()\n        \n        print(f\"   Tensor memory: {self.data.element_size() * self.data.nelement() / 1e9:.2f} GB\")\n    \n    def __len__(self):\n        return len(self.data)\n    \n    def __getitem__(self, idx):\n        return self.data[idx]\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:35:35.245574Z\",\"iopub.execute_input\":\"2025-12-10T09:35:35.245768Z\",\"iopub.status.idle\":\"2025-12-10T09:35:35.268365Z\",\"shell.execute_reply.started\":\"2025-12-10T09:35:35.245752Z\",\"shell.execute_reply\":\"2025-12-10T09:35:35.267838Z\"}}\n# =============================================================================\n# 🎯 SELF-ATTENTION MODULE\n# =============================================================================\n\nclass SelfAttention(nn.Module):\n    \"\"\"Self-attention for capturing long-range dependencies\"\"\"\n    \n    def __init__(self, in_channels):\n        super(SelfAttention, self).__init__()\n        self.query = nn.Conv2d(in_channels, in_channels // 8, 1)\n        self.key = nn.Conv2d(in_channels, in_channels // 8, 1)\n        self.value = nn.Conv2d(in_channels, in_channels, 1)\n        self.gamma = nn.Parameter(torch.zeros(1))\n        self.softmax = nn.Softmax(dim=-1)\n    \n    def forward(self, x):\n        batch, C, H, W = x.size()\n        query = self.query(x).view(batch, -1, H * W).permute(0, 2, 1)\n        key = self.key(x).view(batch, -1, H * W)\n        value = self.value(x).view(batch, -1, H * W)\n        attention = self.softmax(torch.bmm(query, key))\n        out = torch.bmm(value, attention.permute(0, 2, 1))\n        out = out.view(batch, C, H, W)\n        return self.gamma * out + x\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:35:35.269785Z\",\"iopub.execute_input\":\"2025-12-10T09:35:35.270466Z\",\"iopub.status.idle\":\"2025-12-10T09:35:35.294903Z\",\"shell.execute_reply.started\":\"2025-12-10T09:35:35.270449Z\",\"shell.execute_reply\":\"2025-12-10T09:35:35.294355Z\"}}\n# =============================================================================\n# 🎯 OPTIMIZED GENERATOR (With Self-Attention)\n# =============================================================================\n\nclass OptimizedGenerator(nn.Module):\n    \"\"\"Full-capacity Generator with Self-Attention\"\"\"\n    \n    def __init__(self, latent_dim=128, channels=1, features=64, use_attention=True):\n        super(OptimizedGenerator, self).__init__()\n        self.latent_dim = latent_dim\n        self.use_attention = use_attention\n        \n        # Initial projection\n        self.fc = nn.Linear(latent_dim, 4 * 4 * features * 8)\n        self.bn_fc = nn.BatchNorm1d(4 * 4 * features * 8)\n        \n        # Upsampling blocks\n        self.up1 = self._make_block(features * 8, features * 8)  # 4->8\n        self.up2 = self._make_block(features * 8, features * 4)  # 8->16\n        self.up3 = self._make_block(features * 4, features * 4)  # 16->32\n        \n        # Self-attention at 32x32 (captures global structure)\n        if use_attention:\n            self.attention = SelfAttention(features * 4)\n        \n        self.up4 = self._make_block(features * 4, features * 2)  # 32->64\n        self.up5 = self._make_block(features * 2, features)      # 64->128\n        \n        # Final\n        self.final = nn.Sequential(\n            nn.BatchNorm2d(features),\n            nn.ReLU(True),\n            nn.Conv2d(features, channels, 3, 1, 1),\n            nn.Tanh()\n        )\n        \n        self.apply(self._init_weights)\n    \n    def _make_block(self, in_ch, out_ch):\n        return nn.Sequential(\n            nn.ConvTranspose2d(in_ch, out_ch, 4, 2, 1, bias=False),\n            nn.BatchNorm2d(out_ch),\n            nn.ReLU(True)\n        )\n    \n    def _init_weights(self, m):\n        if isinstance(m, (nn.Conv2d, nn.ConvTranspose2d, nn.Linear)):\n            nn.init.normal_(m.weight, 0.0, 0.02)\n        elif isinstance(m, (nn.BatchNorm2d, nn.BatchNorm1d)):\n            nn.init.normal_(m.weight, 1.0, 0.02)\n            nn.init.constant_(m.bias, 0)\n    \n    def forward(self, z):\n        x = self.fc(z)\n        x = self.bn_fc(x)\n        x = F.relu(x)\n        x = x.view(-1, 512, 4, 4)\n        \n        x = self.up1(x)  # 8\n        x = self.up2(x)  # 16\n        x = self.up3(x)  # 32\n        \n        if self.use_attention:\n            x = self.attention(x)\n        \n        x = self.up4(x)  # 64\n        x = self.up5(x)  # 128\n        \n        return self.final(x)\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:35:35.295697Z\",\"iopub.execute_input\":\"2025-12-10T09:35:35.296414Z\",\"iopub.status.idle\":\"2025-12-10T09:35:35.319971Z\",\"shell.execute_reply.started\":\"2025-12-10T09:35:35.296392Z\",\"shell.execute_reply\":\"2025-12-10T09:35:35.319432Z\"}}\n# =============================================================================\n# 🎯 OPTIMIZED DISCRIMINATOR (With Self-Attention + Spectral Norm)\n# =============================================================================\n\nclass OptimizedDiscriminator(nn.Module):\n    \"\"\"Full-capacity Discriminator with Self-Attention\"\"\"\n    \n    def __init__(self, channels=1, features=64, use_attention=True):\n        super(OptimizedDiscriminator, self).__init__()\n        self.use_attention = use_attention\n        \n        # Downsampling blocks (no BatchNorm for WGAN-GP!)\n        self.down1 = self._make_block(channels, features, first=True)      # 128->64\n        self.down2 = self._make_block(features, features * 2)              # 64->32\n        self.down3 = self._make_block(features * 2, features * 4)          # 32->16\n        \n        # Self-attention at 16x16\n        if use_attention:\n            self.attention = SelfAttention(features * 4)\n        \n        self.down4 = self._make_block(features * 4, features * 8)          # 16->8\n        self.down5 = self._make_block(features * 8, features * 8)          # 8->4\n        \n        # Final\n        self.final = spectral_norm(nn.Conv2d(features * 8, 1, 4, 1, 0))\n        \n        self.apply(self._init_weights)\n    \n    def _make_block(self, in_ch, out_ch, first=False):\n        layers = [spectral_norm(nn.Conv2d(in_ch, out_ch, 4, 2, 1))]\n        if not first:\n            layers.append(nn.InstanceNorm2d(out_ch, affine=True))\n        layers.append(nn.LeakyReLU(0.2, inplace=True))\n        return nn.Sequential(*layers)\n    \n    def _init_weights(self, m):\n        if isinstance(m, nn.Conv2d):\n            nn.init.normal_(m.weight, 0.0, 0.02)\n    \n    def forward(self, x):\n        x = self.down1(x)  # 64\n        x = self.down2(x)  # 32\n        x = self.down3(x)  # 16\n        \n        if self.use_attention:\n            x = self.attention(x)\n        \n        x = self.down4(x)  # 8\n        x = self.down5(x)  # 4\n        \n        return self.final(x).view(-1, 1)\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:35:35.320654Z\",\"iopub.execute_input\":\"2025-12-10T09:35:35.321318Z\",\"iopub.status.idle\":\"2025-12-10T09:35:35.346733Z\",\"shell.execute_reply.started\":\"2025-12-10T09:35:35.321296Z\",\"shell.execute_reply\":\"2025-12-10T09:35:35.346122Z\"}}\n# =============================================================================\n# 🎯 EMA (Exponential Moving Average) & GRADIENT PENALTY\n# =============================================================================\n\nclass EMA:\n    \"\"\"EMA for smoother generator outputs\"\"\"\n    \n    def __init__(self, model, decay=0.999):\n        self.model = model\n        self.decay = decay\n        self.shadow = {}\n        self.backup = {}\n        \n        for name, param in model.named_parameters():\n            if param.requires_grad:\n                self.shadow[name] = param.data.clone()\n    \n    def update(self):\n        for name, param in self.model.named_parameters():\n            if param.requires_grad:\n                self.shadow[name] = self.decay * self.shadow[name] + (1 - self.decay) * param.data\n    \n    def apply_shadow(self):\n        for name, param in self.model.named_parameters():\n            if param.requires_grad:\n                self.backup[name] = param.data.clone()\n                param.data = self.shadow[name]\n    \n    def restore(self):\n        for name, param in self.model.named_parameters():\n            if param.requires_grad:\n                param.data = self.backup[name]\n\n\ndef compute_gradient_penalty(discriminator, real_samples, fake_samples, device):\n    \"\"\"Standard WGAN-GP gradient penalty\"\"\"\n    batch_size = real_samples.size(0)\n    alpha = torch.rand(batch_size, 1, 1, 1, device=device)\n    \n    interpolates = (alpha * real_samples + (1 - alpha) * fake_samples).requires_grad_(True)\n    d_interpolates = discriminator(interpolates)\n    \n    gradients = torch.autograd.grad(\n        outputs=d_interpolates,\n        inputs=interpolates,\n        grad_outputs=torch.ones_like(d_interpolates),\n        create_graph=True,\n        retain_graph=True,\n        only_inputs=True\n    )[0]\n    \n    gradients = gradients.view(batch_size, -1)\n    gradient_penalty = ((gradients.norm(2, dim=1) - 1) ** 2).mean()\n    \n    return gradient_penalty\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:35:35.347484Z\",\"iopub.execute_input\":\"2025-12-10T09:35:35.347748Z\",\"iopub.status.idle\":\"2025-12-10T09:35:35.371747Z\",\"shell.execute_reply.started\":\"2025-12-10T09:35:35.347712Z\",\"shell.execute_reply\":\"2025-12-10T09:35:35.371231Z\"}}\n# =============================================================================\n# 🛡️ RAM-SAFE EVALUATION METRICS\n# =============================================================================\n\nclass RAMSafeMetrics:\n    \"\"\"RAM-Safe evaluation metrics - O(N) instead of O(N²)\"\"\"\n    \n    @staticmethod\n    def compute(generator, dataloader, config, device):\n        \"\"\"Compute RAM-safe metrics\"\"\"\n        generator.eval()\n        metrics = {}\n        \n        n_samples = config.EVAL_SAMPLE_SIZE  # 64, not 1000!\n        \n        with torch.no_grad():\n            # Generate fake samples\n            z = torch.randn(n_samples, config.LATENT_DIM).to(device)\n            fake = generator(z)\n            fake = (fake + 1) / 2.0  # [-1,1] -> [0,1]\n            fake_np = fake.cpu().numpy()\n            \n            # Get real samples\n            real_list = []\n            for batch in dataloader:\n                real = batch.to(device)\n                real = (real + 1) / 2.0\n                real_list.append(real.cpu().numpy())\n                if sum(len(r) for r in real_list) >= n_samples:\n                    break\n            real_np = np.concatenate(real_list, axis=0)[:n_samples]\n            \n            # METRIC 1: SSIM vs Real (O(N), not O(N²)!)\n            ssim_scores = []\n            for i in range(min(32, n_samples)):\n                fake_img = fake_np[i, 0]\n                real_idx = np.random.randint(len(real_np))\n                real_img = real_np[real_idx, 0]\n                score = ssim(fake_img, real_img, data_range=1.0)\n                ssim_scores.append(score)\n            metrics['ssim_vs_real'] = float(np.mean(ssim_scores))\n            \n            # METRIC 2: Pixel Diversity (O(N) - no pairwise!)\n            pixel_variance = np.var(fake_np, axis=0).mean()\n            metrics['pixel_diversity'] = float(pixel_variance)\n            \n            means = [img.mean() for img in fake_np[:, 0]]\n            stds = [img.std() for img in fake_np[:, 0]]\n            metrics['mean_diversity'] = float(np.std(means))\n            metrics['std_diversity'] = float(np.std(stds))\n            \n            # METRIC 3: Image Statistics\n            metrics['fake_mean'] = float(np.mean(fake_np))\n            metrics['fake_std'] = float(np.std(fake_np))\n            metrics['real_mean'] = float(np.mean(real_np))\n            metrics['real_std'] = float(np.std(real_np))\n            \n            # METRIC 4: Edge Sharpness\n            from scipy import ndimage\n            edge_scores = []\n            for i in range(min(16, n_samples)):\n                img = fake_np[i, 0]\n                sobel_x = ndimage.sobel(img, axis=0)\n                sobel_y = ndimage.sobel(img, axis=1)\n                edge_magnitude = np.sqrt(sobel_x**2 + sobel_y**2)\n                edge_scores.append(edge_magnitude.mean())\n            metrics['edge_sharpness'] = float(np.mean(edge_scores))\n            \n            # Cleanup\n            del fake, fake_np, real_np, real_list\n            gc.collect()\n        \n        generator.train()\n        return metrics\n    \n    @staticmethod\n    def print_metrics(metrics, epoch):\n        \"\"\"Pretty print metrics\"\"\"\n        print(f\"\\n📊 Evaluation Metrics (Epoch {epoch}):\")\n        print(f\"   SSIM vs Real:     {metrics['ssim_vs_real']:.4f}  (higher = more similar)\")\n        print(f\"   Pixel Diversity:  {metrics['pixel_diversity']:.4f}  (higher = more variety)\")\n        print(f\"   Mean Diversity:   {metrics['mean_diversity']:.4f}\")\n        print(f\"   Edge Sharpness:   {metrics['edge_sharpness']:.4f}\")\n        print(f\"   Fake Mean/Std:    {metrics['fake_mean']:.3f} / {metrics['fake_std']:.3f}\")\n        print(f\"   Real Mean/Std:    {metrics['real_mean']:.3f} / {metrics['real_std']:.3f}\")\n        \n        if metrics['ssim_vs_real'] > 0.5:\n            print(\"   ✅ Good structural similarity to real MRIs\")\n        elif metrics['ssim_vs_real'] > 0.3:\n            print(\"   ⚠️ Moderate similarity - training progressing\")\n        else:\n            print(\"   ❌ Low similarity - early training phase\")\n        \n        if metrics['pixel_diversity'] > 0.02:\n            print(\"   ✅ Good diversity - no mode collapse\")\n        else:\n            print(\"   ⚠️ Low diversity - watch for mode collapse\")\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:35:35.372553Z\",\"iopub.execute_input\":\"2025-12-10T09:35:35.372826Z\",\"iopub.status.idle\":\"2025-12-10T09:35:35.402191Z\",\"shell.execute_reply.started\":\"2025-12-10T09:35:35.372800Z\",\"shell.execute_reply\":\"2025-12-10T09:35:35.401493Z\"}}\n# =============================================================================\n# ⚖️ BALANCED TRAINER (Kaggle-Optimized)\n# =============================================================================\n\nclass BalancedTrainer:\n    \"\"\"Balanced Trainer: Full Quality + RAM-Safe\"\"\"\n    \n    def __init__(self, dataloader, config):\n        self.config = config\n        self.dataloader = dataloader\n        self.device = config.DEVICE\n        \n        print(\"\\n\" + \"=\" * 70)\n        print(\"⚖️ INITIALIZING BALANCED TRAINER\")\n        print(\"=\" * 70)\n        \n        # Full-capacity models with self-attention\n        self.generator = OptimizedGenerator(\n            config.LATENT_DIM, \n            channels=1, \n            features=config.GEN_FEATURES,\n            use_attention=config.USE_SELF_ATTENTION\n        ).to(self.device)\n        \n        self.discriminator = OptimizedDiscriminator(\n            channels=1, \n            features=config.DISC_FEATURES,\n            use_attention=config.USE_SELF_ATTENTION\n        ).to(self.device)\n        \n        g_params = sum(p.numel() for p in self.generator.parameters())\n        d_params = sum(p.numel() for p in self.discriminator.parameters())\n        \n        print(f\"✅ Generator: {g_params:,} params\")\n        print(f\"✅ Discriminator: {d_params:,} params\")\n        print(f\"   Self-Attention: {'ON ✅' if config.USE_SELF_ATTENTION else 'OFF'}\")\n        \n        # EMA\n        self.ema = None\n        if config.USE_EMA:\n            self.ema = EMA(self.generator, decay=config.EMA_DECAY)\n            print(f\"✅ EMA: ON (decay={config.EMA_DECAY})\")\n        \n        # Optimizers\n        self.optimizer_g = Adam(\n            self.generator.parameters(),\n            lr=config.LR_G,\n            betas=(config.BETA1, config.BETA2)\n        )\n        \n        self.optimizer_d = Adam(\n            self.discriminator.parameters(),\n            lr=config.LR_D,\n            betas=(config.BETA1, config.BETA2)\n        )\n        \n        # Tracking\n        self.g_losses = []\n        self.d_losses = []\n        self.metrics_history = []\n        \n        print(\"=\" * 70)\n    \n    def train_epoch(self, epoch):\n        self.generator.train()\n        self.discriminator.train()\n        \n        pbar = tqdm(self.dataloader, desc=f\"Epoch {epoch}/{self.config.EPOCHS}\")\n        epoch_g_losses = []\n        epoch_d_losses = []\n        \n        for batch_idx, real_images in enumerate(pbar):\n            real_images = real_images.to(self.device)\n            batch_size = real_images.size(0)\n            \n            # Train Discriminator\n            for _ in range(self.config.N_CRITIC):\n                self.optimizer_d.zero_grad()\n                \n                real_output = self.discriminator(real_images)\n                \n                z = torch.randn(batch_size, self.config.LATENT_DIM, device=self.device)\n                fake_images = self.generator(z)\n                fake_output = self.discriminator(fake_images.detach())\n                \n                d_loss = fake_output.mean() - real_output.mean()\n                gp = compute_gradient_penalty(\n                    self.discriminator, real_images, fake_images.detach(), self.device\n                )\n                d_loss = d_loss + self.config.LAMBDA_GP * gp\n                \n                d_loss.backward()\n                torch.nn.utils.clip_grad_norm_(\n                    self.discriminator.parameters(), self.config.GRADIENT_CLIP_NORM\n                )\n                self.optimizer_d.step()\n            \n            # Train Generator\n            self.optimizer_g.zero_grad()\n            \n            z = torch.randn(batch_size, self.config.LATENT_DIM, device=self.device)\n            fake_images = self.generator(z)\n            g_output = self.discriminator(fake_images)\n            g_loss = -g_output.mean()\n            \n            g_loss.backward()\n            torch.nn.utils.clip_grad_norm_(\n                self.generator.parameters(), self.config.GRADIENT_CLIP_NORM\n            )\n            self.optimizer_g.step()\n            \n            # Update EMA\n            if self.ema:\n                self.ema.update()\n            \n            # Track - only keep last value per batch to save memory\n            g_loss_val = g_loss.item()\n            d_loss_val = d_loss.item()\n            epoch_g_losses.append(g_loss_val)\n            epoch_d_losses.append(d_loss_val)\n            \n            # Only keep last 500 losses to prevent memory buildup\n            if len(self.g_losses) > 500:\n                self.g_losses = self.g_losses[-250:]\n                self.d_losses = self.d_losses[-250:]\n            self.g_losses.append(g_loss_val)\n            self.d_losses.append(d_loss_val)\n            \n            if np.isnan(g_loss_val) or np.isnan(d_loss_val):\n                raise ValueError(\"NaN detected!\")\n            \n            pbar.set_postfix({'G': f'{g_loss_val:.4f}', 'D': f'{d_loss_val:.4f}'})\n            \n            # Aggressive GC every 25 batches\n            if batch_idx % 25 == 0:\n                gc.collect()\n                torch.cuda.empty_cache()\n        \n        # End of epoch cleanup\n        gc.collect()\n        torch.cuda.empty_cache()\n        \n        return np.mean(epoch_g_losses), np.mean(epoch_d_losses)\n    \n    def evaluate(self, epoch):\n        \"\"\"RAM-safe evaluation\"\"\"\n        if self.ema:\n            self.ema.apply_shadow()\n        \n        metrics = RAMSafeMetrics.compute(\n            self.generator, self.dataloader, self.config, self.device\n        )\n        metrics['epoch'] = epoch\n        self.metrics_history.append(metrics)\n        \n        RAMSafeMetrics.print_metrics(metrics, epoch)\n        \n        if self.ema:\n            self.ema.restore()\n        \n        self.save_samples(epoch)\n        gc.collect()\n        return metrics\n    \n    def save_samples(self, epoch, n_samples=16, show=True):\n        \"\"\"Save and display sample grid\"\"\"\n        if self.ema:\n            self.ema.apply_shadow()\n        \n        self.generator.eval()\n        with torch.no_grad():\n            z = torch.randn(n_samples, self.config.LATENT_DIM).to(self.device)\n            fake = self.generator(z)\n            fake = (fake + 1) / 2.0\n            fake = torch.clamp(fake, 0, 1)\n            \n            fig, axes = plt.subplots(4, 4, figsize=(10, 10))\n            for i, ax in enumerate(axes.flat):\n                ax.imshow(fake[i].cpu().squeeze().numpy(), cmap='gray')\n                ax.axis('off')\n            plt.suptitle(f'Epoch {epoch} (EMA)', fontsize=14)\n            plt.tight_layout()\n            plt.savefig(os.path.join(self.config.CHECKPOINT_DIR, f'samples_{epoch:04d}.png'))\n            if show:\n                plt.show()\n            plt.close()\n        \n        if self.ema:\n            self.ema.restore()\n        \n        self.generator.train()\n    \n    def train(self, num_epochs, save_every=20, start_epoch=1):\n        print(\"\\n\" + \"=\" * 70)\n        print(\"🚀 STARTING BALANCED TRAINING - 40 EPOCH RUN\")\n        print(\"=\" * 70)\n        print(f\"📋 Schedule:\")\n        print(f\"   • Total epochs: {num_epochs}\")\n        print(f\"   • Checkpoint & Evaluate at: epoch 20, 40\")\n        print(f\"   • Samples saved at: epoch 20, 40\")\n        print(\"=\" * 70)\n        \n        for epoch in range(start_epoch, num_epochs + 1):\n            try:\n                avg_g_loss, avg_d_loss = self.train_epoch(epoch)\n                print(f\"\\n✓ Epoch {epoch}/{num_epochs}: G_loss={avg_g_loss:.4f}, D_loss={avg_d_loss:.4f}\")\n                \n                # Evaluate ONLY at epoch 20 and 40\n                if epoch % self.config.EVAL_INTERVAL == 0:\n                    print(f\"\\n📊 Running evaluation at epoch {epoch}...\")\n                    self.evaluate(epoch)\n                \n                # Save checkpoint ONLY at epoch 20 and 40\n                if epoch % save_every == 0:\n                    self.save_checkpoint(epoch)\n                \n                # Print memory status every 10 epochs\n                if epoch % 10 == 0:\n                    print_memory_status()\n                \n                # Aggressive cleanup after each epoch\n                gc.collect()\n                torch.cuda.empty_cache()\n                \n            except ValueError as e:\n                print(f\"⚠️ Training stopped: {e}\")\n                self.save_checkpoint(epoch)\n                break\n            except RuntimeError as e:\n                if \"out of memory\" in str(e).lower():\n                    print(f\"⚠️ OOM at epoch {epoch}! Saving checkpoint...\")\n                    gc.collect()\n                    torch.cuda.empty_cache()\n                    self.save_checkpoint(epoch)\n                raise\n        \n        print(\"\\n\" + \"=\" * 70)\n        print(\"✅ TRAINING COMPLETE - 40 EPOCHS FINISHED!\")\n        print(\"=\" * 70)\n    \n    def save_checkpoint(self, epoch):\n        checkpoint = {\n            'epoch': epoch,\n            'generator_state_dict': self.generator.state_dict(),\n            'discriminator_state_dict': self.discriminator.state_dict(),\n            'optimizer_g': self.optimizer_g.state_dict(),\n            'optimizer_d': self.optimizer_d.state_dict(),\n            'g_losses': self.g_losses[-1000:],\n            'd_losses': self.d_losses[-1000:],\n            'metrics_history': self.metrics_history,\n        }\n        \n        if self.ema:\n            checkpoint['ema_shadow'] = self.ema.shadow\n        \n        path = os.path.join(self.config.CHECKPOINT_DIR, f'checkpoint_{epoch:04d}.pth')\n        torch.save(checkpoint, path)\n        print(f\"   💾 Checkpoint saved: epoch {epoch}\")\n        \n        # Also save as 'latest'\n        latest_path = os.path.join(self.config.CHECKPOINT_DIR, 'checkpoint_latest.pth')\n        torch.save(checkpoint, latest_path)\n        \n        # Zip for download\n        zip_path = os.path.join(self.config.CHECKPOINT_DIR, f'checkpoint_{epoch:04d}.zip')\n        with zipfile.ZipFile(zip_path, 'w', zipfile.ZIP_DEFLATED) as zipf:\n            zipf.write(path, os.path.basename(path))\n        size_mb = os.path.getsize(zip_path) / (1024*1024)\n        print(f\"   📦 Backup: {size_mb:.1f} MB\")\n    \n    def load_checkpoint(self, path):\n        checkpoint = torch.load(path, map_location=self.device)\n        self.generator.load_state_dict(checkpoint['generator_state_dict'])\n        self.discriminator.load_state_dict(checkpoint['discriminator_state_dict'])\n        self.optimizer_g.load_state_dict(checkpoint['optimizer_g'])\n        self.optimizer_d.load_state_dict(checkpoint['optimizer_d'])\n        if self.ema and 'ema_shadow' in checkpoint:\n            self.ema.shadow = checkpoint['ema_shadow']\n        self.g_losses = checkpoint.get('g_losses', [])\n        self.d_losses = checkpoint.get('d_losses', [])\n        self.metrics_history = checkpoint.get('metrics_history', [])\n        print(f\"✅ Loaded: epoch {checkpoint['epoch']}\")\n        return checkpoint['epoch']\n    \n    def generate_synthetic_dataset(self, num_samples, output_dir):\n        \"\"\"Generate using EMA weights\"\"\"\n        os.makedirs(output_dir, exist_ok=True)\n        \n        if self.ema:\n            self.ema.apply_shadow()\n            print(\"   Using EMA weights for best quality\")\n        \n        self.generator.eval()\n        batch_size = 64\n        \n        from PIL import Image\n        \n        with torch.no_grad():\n            for i in tqdm(range(0, num_samples, batch_size), desc=\"Generating\"):\n                bs = min(batch_size, num_samples - i)\n                z = torch.randn(bs, self.config.LATENT_DIM).to(self.device)\n                fake = self.generator(z)\n                fake = (fake + 1) / 2.0\n                fake = torch.clamp(fake, 0, 1)\n                \n                for j, img in enumerate(fake):\n                    img_np = (img.cpu().squeeze().numpy() * 255).astype(np.uint8)\n                    Image.fromarray(img_np, mode='L').save(\n                        os.path.join(output_dir, f'synthetic_ftd_{i+j:06d}.png')\n                    )\n                \n                del fake, z\n                if i % 1000 == 0:\n                    gc.collect()\n                    torch.cuda.empty_cache()\n        \n        if self.ema:\n            self.ema.restore()\n        \n        print(f\"\\n✅ Generated {num_samples:,} images\")\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:35:35.402831Z\",\"iopub.execute_input\":\"2025-12-10T09:35:35.403071Z\",\"iopub.status.idle\":\"2025-12-10T09:35:36.359600Z\",\"shell.execute_reply.started\":\"2025-12-10T09:35:35.403049Z\",\"shell.execute_reply\":\"2025-12-10T09:35:36.358841Z\"}}\n# =============================================================================\n# 📂 LOAD DATA\n# =============================================================================\n\nprint(\"=\" * 70)\nprint(\"⚖️ DementiaNext FTD GAN - KAGGLE VERSION\")\nprint(\"=\" * 70)\n\n# RAM check\nprint_memory_status()\n\n# Find data\nnifti_paths = []\nif os.path.exists(config.DATA_DIR):\n    for root, dirs, files in os.walk(config.DATA_DIR):\n        for f in files:\n            if f.endswith('.nii') or f.endswith('.nii.gz'):\n                nifti_paths.append(os.path.join(root, f))\n\nprint(f\"\\n📂 Found {len(nifti_paths)} NIfTI files\")\n\nif len(nifti_paths) == 0:\n    print(f\"\\n❌ No NIfTI files found in {config.DATA_DIR}\")\n    print(\"\")\n    print(\"🔧 To fix this:\")\n    print(\"   1. Click 'Add Data' in the right sidebar\")\n    print(\"   2. Add your NIfTI dataset\")\n    print(\"   3. Run: !find /kaggle/input -name '*.nii*' | head -10\")\n    print(\"   4. Update DATA_DIR in the Configuration cell\")\nelse:\n    print(f\"   First file: {nifti_paths[0]}\")\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:35:36.360393Z\",\"iopub.execute_input\":\"2025-12-10T09:35:36.360624Z\",\"iopub.status.idle\":\"2025-12-10T09:38:48.869177Z\",\"shell.execute_reply.started\":\"2025-12-10T09:35:36.360597Z\",\"shell.execute_reply\":\"2025-12-10T09:38:48.868364Z\"}}\n# =============================================================================\n# 📊 CREATE DATASET & DATALOADER\n# =============================================================================\n\nif len(nifti_paths) > 0:\n    # Dataset\n    dataset = RAMSafeDataset(nifti_paths, config)\n    \n    dataloader = DataLoader(\n        dataset,\n        batch_size=config.BATCH_SIZE,\n        shuffle=True,\n        num_workers=0,  # Important for Kaggle stability\n        pin_memory=True,\n        drop_last=True\n    )\n    \n    print(f\"\\n📊 DataLoader:\")\n    print(f\"   Samples: {len(dataset):,}\")\n    print(f\"   Batch size: {config.BATCH_SIZE}\")\n    print(f\"   Batches/epoch: {len(dataloader)}\")\n    \n    # Show sample\n    sample_batch = next(iter(dataloader))\n    print(f\"   Sample shape: {sample_batch.shape}\")\n    \n    # Visualize real samples\n    fig, axes = plt.subplots(2, 4, figsize=(12, 6))\n    for i, ax in enumerate(axes.flat):\n        img = (sample_batch[i].squeeze().numpy() + 1) / 2  # [-1,1] -> [0,1]\n        ax.imshow(img, cmap='gray')\n        ax.axis('off')\n    plt.suptitle('Real Training Samples', fontsize=14)\n    plt.tight_layout()\n    plt.show()\n    \n    print_memory_status()\nelse:\n    print(\"⚠️ Cannot create dataset - no data found!\")\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:38:48.869884Z\",\"iopub.execute_input\":\"2025-12-10T09:38:48.870104Z\",\"iopub.status.idle\":\"2025-12-10T09:38:49.090274Z\",\"shell.execute_reply.started\":\"2025-12-10T09:38:48.870089Z\",\"shell.execute_reply\":\"2025-12-10T09:38:49.089675Z\"}}\n# =============================================================================\n# 🎓 CREATE TRAINER\n# =============================================================================\n\nif len(nifti_paths) > 0:\n    trainer = BalancedTrainer(dataloader, config)\n    \n    # Time estimate for 40 epochs\n    batches_per_epoch = len(dataloader)\n    total_batches = batches_per_epoch * config.EPOCHS\n    # Estimate ~0.5 seconds per batch on Kaggle GPU\n    hours = (total_batches * 0.5) / 3600\n    \n    print(f\"\\n📋 Training Schedule (40 Epochs):\")\n    print(f\"   • Batches per epoch: {batches_per_epoch}\")\n    print(f\"   • Total batches: {total_batches:,}\")\n    print(f\"   • Estimated time: ~{hours:.1f} hours\")\n    print(f\"\")\n    print(f\"   📊 Milestones:\")\n    print(f\"      Epoch 20: Checkpoint + Evaluation + Samples\")\n    print(f\"      Epoch 40: Checkpoint + Evaluation + Samples + Final Results\")\n    \n    if hours > 10:\n        print(f\"\\n⚠️ Note: This may take a while. Checkpoints are saved at epoch 20.\")\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:38:49.090956Z\",\"iopub.execute_input\":\"2025-12-10T09:38:49.091125Z\",\"iopub.status.idle\":\"2025-12-10T09:38:49.095219Z\",\"shell.execute_reply.started\":\"2025-12-10T09:38:49.091111Z\",\"shell.execute_reply\":\"2025-12-10T09:38:49.094674Z\"}}\n# =============================================================================\n# 🔄 OPTIONAL: RESUME FROM CHECKPOINT\n# =============================================================================\n# If your Kaggle session times out, you can:\n# 1. Download the checkpoint from /kaggle/working/checkpoints/\n# 2. Upload it as a dataset\n# 3. Uncomment and run this cell\n\nRESUME_FROM_CHECKPOINT = False  # Set to True to resume\nCHECKPOINT_PATH = '/kaggle/input/your-checkpoint-dataset/checkpoint_latest.pth'\n\nstart_epoch = 1\nif RESUME_FROM_CHECKPOINT and os.path.exists(CHECKPOINT_PATH):\n    start_epoch = trainer.load_checkpoint(CHECKPOINT_PATH) + 1\n    print(f\"\\n🔄 Resuming from epoch {start_epoch}\")\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T09:38:49.097613Z\",\"iopub.execute_input\":\"2025-12-10T09:38:49.097889Z\",\"iopub.status.idle\":\"2025-12-10T15:30:27.863902Z\",\"shell.execute_reply.started\":\"2025-12-10T09:38:49.097873Z\",\"shell.execute_reply\":\"2025-12-10T15:30:27.863231Z\"}}\n# =============================================================================\n# 🚀 TRAIN! (40 Epochs - Checkpoint at 20 and 40)\n# =============================================================================\n\nif len(nifti_paths) > 0:\n    print(\"🚀 Starting 40-epoch training run...\")\n    print(\"   Checkpoints & Evaluation: epoch 20, 40\")\n    print(\"\")\n    \n    trainer.train(\n        num_epochs=config.EPOCHS,  # 40 epochs\n        save_every=config.SAVE_INTERVAL,  # 20 (saves at 20 and 40)\n        start_epoch=start_epoch if 'start_epoch' in dir() else 1\n    )\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T15:30:27.864640Z\",\"iopub.execute_input\":\"2025-12-10T15:30:27.864921Z\",\"iopub.status.idle\":\"2025-12-10T15:30:28.643626Z\",\"shell.execute_reply.started\":\"2025-12-10T15:30:27.864902Z\",\"shell.execute_reply\":\"2025-12-10T15:30:28.643056Z\"}}\n# =============================================================================\n# 📈 TRAINING VISUALIZATION\n# =============================================================================\n\nif len(nifti_paths) > 0 and len(trainer.g_losses) > 0:\n    fig, axes = plt.subplots(1, 2, figsize=(14, 5))\n    \n    # Losses\n    axes[0].plot(trainer.g_losses, label='Generator', alpha=0.7)\n    axes[0].plot(trainer.d_losses, label='Discriminator', alpha=0.7)\n    axes[0].set_xlabel('Iteration')\n    axes[0].set_ylabel('Loss')\n    axes[0].set_title('Training Losses')\n    axes[0].legend()\n    axes[0].grid(True, alpha=0.3)\n    \n    # Metrics\n    if trainer.metrics_history:\n        epochs = [m['epoch'] for m in trainer.metrics_history]\n        ssim_vals = [m['ssim_vs_real'] for m in trainer.metrics_history]\n        div_vals = [m['pixel_diversity'] for m in trainer.metrics_history]\n        \n        ax2 = axes[1]\n        ax2.plot(epochs, ssim_vals, 'b-o', label='SSIM vs Real')\n        ax2.set_xlabel('Epoch')\n        ax2.set_ylabel('SSIM', color='b')\n        ax2.tick_params(axis='y', labelcolor='b')\n        \n        ax3 = ax2.twinx()\n        ax3.plot(epochs, div_vals, 'r-s', label='Pixel Diversity')\n        ax3.set_ylabel('Diversity', color='r')\n        ax3.tick_params(axis='y', labelcolor='r')\n        \n        axes[1].set_title('Evaluation Metrics')\n        axes[1].grid(True, alpha=0.3)\n    \n    plt.tight_layout()\n    plt.savefig(os.path.join(config.OUTPUT_DIR, 'training_curves.png'), dpi=150)\n    plt.show()\n\n\n# %% [code]\n\n\n# %% [code]\n\n\n# %% [code]\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T16:31:02.797058Z\",\"iopub.execute_input\":\"2025-12-10T16:31:02.797748Z\",\"iopub.status.idle\":\"2025-12-10T16:31:07.809509Z\",\"shell.execute_reply.started\":\"2025-12-10T16:31:02.797724Z\",\"shell.execute_reply\":\"2025-12-10T16:31:07.808940Z\"}}\n# =============================================================================\n# 📊 COMPREHENSIVE QUALITY EVALUATION\n# =============================================================================\n# This cell provides detailed quality metrics for generated images\n# Run this after training to get a complete quality report\n\nimport numpy as np\nfrom scipy import ndimage\nfrom skimage.metrics import structural_similarity as ssim\nfrom skimage.metrics import peak_signal_noise_ratio as psnr\nfrom skimage.feature import canny\nfrom collections import defaultdict\nimport matplotlib.pyplot as plt\n\nclass ComprehensiveEvaluator:\n    \"\"\"\n    Comprehensive evaluation of GAN-generated images.\n    Provides per-slice quality scores and overall statistics.\n    \"\"\"\n    \n    def __init__(self, generator, dataloader, config, device, n_samples=500):\n        self.generator = generator\n        self.dataloader = dataloader\n        self.config = config\n        self.device = device\n        self.n_samples = n_samples\n        \n    def generate_samples(self):\n        \"\"\"Generate synthetic samples\"\"\"\n        self.generator.eval()\n        all_fake = []\n        \n        with torch.no_grad():\n            batch_size = 32\n            for i in range(0, self.n_samples, batch_size):\n                bs = min(batch_size, self.n_samples - i)\n                z = torch.randn(bs, self.config.LATENT_DIM).to(self.device)\n                fake = self.generator(z)\n                fake = (fake + 1) / 2.0  # [-1,1] -> [0,1]\n                all_fake.append(fake.cpu().numpy())\n        \n        self.fake_images = np.concatenate(all_fake, axis=0)\n        print(f\"✅ Generated {len(self.fake_images)} synthetic images\")\n        \n        # Get real samples\n        real_list = []\n        for batch in self.dataloader:\n            real = batch.to(self.device)\n            real = (real + 1) / 2.0\n            real_list.append(real.cpu().numpy())\n            if sum(len(r) for r in real_list) >= self.n_samples:\n                break\n        self.real_images = np.concatenate(real_list, axis=0)[:self.n_samples]\n        print(f\"✅ Loaded {len(self.real_images)} real images for comparison\")\n        \n        self.generator.train()\n        \n    def compute_per_slice_metrics(self):\n        \"\"\"Compute quality metrics for each generated slice\"\"\"\n        print(\"\\n📊 Computing per-slice quality metrics...\")\n        \n        self.slice_metrics = []\n        \n        for i in tqdm(range(len(self.fake_images)), desc=\"Evaluating slices\"):\n            fake_img = self.fake_images[i, 0]\n            # Compare to random real image\n            real_idx = np.random.randint(len(self.real_images))\n            real_img = self.real_images[real_idx, 0]\n            \n            metrics = {}\n            \n            # 1. SSIM (Structural Similarity)\n            metrics['ssim'] = ssim(fake_img, real_img, data_range=1.0)\n            \n            # 2. PSNR (Peak Signal-to-Noise Ratio)\n            metrics['psnr'] = psnr(real_img, fake_img, data_range=1.0)\n            \n            # 3. Mean Absolute Error\n            metrics['mae'] = np.mean(np.abs(fake_img - real_img))\n            \n            # 4. Brain Content Ratio (non-zero pixels)\n            metrics['brain_ratio'] = np.sum(fake_img > 0.05) / fake_img.size\n            \n            # 5. Edge Density (anatomical detail)\n            sobel_x = ndimage.sobel(fake_img, axis=0)\n            sobel_y = ndimage.sobel(fake_img, axis=1)\n            edge_magnitude = np.sqrt(sobel_x**2 + sobel_y**2)\n            metrics['edge_density'] = edge_magnitude.mean()\n            \n            # 6. Contrast (std of non-zero pixels)\n            brain_pixels = fake_img[fake_img > 0.05]\n            metrics['contrast'] = brain_pixels.std() if len(brain_pixels) > 0 else 0\n            \n            # 7. Intensity Range\n            metrics['intensity_range'] = fake_img.max() - fake_img.min()\n            \n            # 8. Smoothness (inverse of Laplacian variance)\n            laplacian = ndimage.laplace(fake_img)\n            metrics['smoothness'] = 1 / (np.var(laplacian) + 1e-8)\n            \n            # 9. Symmetry Score (brain should be roughly symmetric)\n            flipped = np.fliplr(fake_img)\n            metrics['symmetry'] = 1 - np.mean(np.abs(fake_img - flipped))\n            \n            self.slice_metrics.append(metrics)\n        \n        # Convert to numpy arrays for easy analysis\n        self.metrics_df = {key: np.array([m[key] for m in self.slice_metrics]) \n                          for key in self.slice_metrics[0].keys()}\n        \n    def classify_quality(self):\n        \"\"\"Classify each slice as Good, Medium, or Poor quality\"\"\"\n        print(\"\\n🏷️ Classifying slice quality...\")\n        \n        # Define thresholds\n        ssim_scores = self.metrics_df['ssim']\n        brain_ratios = self.metrics_df['brain_ratio']\n        \n        self.quality_labels = []\n        \n        for i in range(len(self.fake_images)):\n            ssim_val = ssim_scores[i]\n            brain_ratio = brain_ratios[i]\n            \n            # Quality classification rules\n            if ssim_val >= 0.5 and brain_ratio >= 0.15:\n                quality = 'GOOD'\n            elif ssim_val >= 0.35 and brain_ratio >= 0.10:\n                quality = 'MEDIUM'\n            else:\n                quality = 'POOR'\n            \n            self.quality_labels.append(quality)\n        \n        # Count\n        self.quality_counts = {\n            'GOOD': self.quality_labels.count('GOOD'),\n            'MEDIUM': self.quality_labels.count('MEDIUM'),\n            'POOR': self.quality_labels.count('POOR')\n        }\n        \n    def compute_diversity_metrics(self):\n        \"\"\"Compute diversity metrics across all generated images\"\"\"\n        print(\"\\n🎨 Computing diversity metrics...\")\n        \n        self.diversity_metrics = {}\n        \n        # 1. Pixel-wise variance (mode collapse check)\n        pixel_variance = np.var(self.fake_images, axis=0).mean()\n        self.diversity_metrics['pixel_variance'] = pixel_variance\n        \n        # 2. Mean intensity diversity\n        means = [img.mean() for img in self.fake_images[:, 0]]\n        self.diversity_metrics['mean_diversity'] = np.std(means)\n        \n        # 3. Std intensity diversity\n        stds = [img.std() for img in self.fake_images[:, 0]]\n        self.diversity_metrics['std_diversity'] = np.std(stds)\n        \n        # 4. Pairwise SSIM diversity (sample 50 pairs)\n        pairwise_ssim = []\n        for _ in range(50):\n            i, j = np.random.choice(len(self.fake_images), 2, replace=False)\n            score = ssim(self.fake_images[i, 0], self.fake_images[j, 0], data_range=1.0)\n            pairwise_ssim.append(score)\n        self.diversity_metrics['pairwise_ssim_mean'] = np.mean(pairwise_ssim)\n        self.diversity_metrics['pairwise_ssim_std'] = np.std(pairwise_ssim)\n        \n        # 5. Unique patterns check (clustering proxy)\n        # Low pairwise SSIM = more diverse\n        self.diversity_metrics['diversity_score'] = 1 - self.diversity_metrics['pairwise_ssim_mean']\n        \n    def compute_realism_metrics(self):\n        \"\"\"Compare fake statistics to real statistics\"\"\"\n        print(\"\\n🔬 Computing realism metrics...\")\n        \n        self.realism_metrics = {}\n        \n        # Statistics comparison\n        fake_means = [img.mean() for img in self.fake_images[:, 0]]\n        real_means = [img.mean() for img in self.real_images[:, 0]]\n        fake_stds = [img.std() for img in self.fake_images[:, 0]]\n        real_stds = [img.std() for img in self.real_images[:, 0]]\n        \n        # Mean distribution match\n        self.realism_metrics['mean_match'] = 1 - abs(np.mean(fake_means) - np.mean(real_means))\n        self.realism_metrics['std_match'] = 1 - abs(np.mean(fake_stds) - np.mean(real_stds))\n        \n        # Histogram intersection (intensity distribution match)\n        fake_hist, _ = np.histogram(self.fake_images.flatten(), bins=50, range=(0, 1), density=True)\n        real_hist, _ = np.histogram(self.real_images.flatten(), bins=50, range=(0, 1), density=True)\n        self.realism_metrics['histogram_intersection'] = np.minimum(fake_hist, real_hist).sum() / fake_hist.sum()\n        \n        # Edge density comparison\n        fake_edges = [ndimage.sobel(img[0]).mean() for img in self.fake_images[:100]]\n        real_edges = [ndimage.sobel(img[0]).mean() for img in self.real_images[:100]]\n        self.realism_metrics['edge_match'] = 1 - abs(np.mean(fake_edges) - np.mean(real_edges)) / np.mean(real_edges)\n        \n    def print_report(self):\n        \"\"\"Print comprehensive quality report\"\"\"\n        print(\"\\n\" + \"=\"*70)\n        print(\"📊 COMPREHENSIVE GAN QUALITY REPORT\")\n        print(\"=\"*70)\n        \n        # Quality Distribution\n        print(\"\\n🏷️ QUALITY DISTRIBUTION:\")\n        print(\"-\"*40)\n        total = len(self.quality_labels)\n        for quality, count in self.quality_counts.items():\n            pct = count / total * 100\n            bar = '█' * int(pct / 2)\n            print(f\"   {quality:8s}: {count:4d} ({pct:5.1f}%) {bar}\")\n        \n        good_pct = self.quality_counts['GOOD'] / total * 100\n        usable_pct = (self.quality_counts['GOOD'] + self.quality_counts['MEDIUM']) / total * 100\n        \n        print(f\"\\n   ✅ Good Quality:    {good_pct:.1f}%\")\n        print(f\"   ✅ Usable (Good+Med): {usable_pct:.1f}%\")\n        \n        # Per-Slice Statistics\n        print(\"\\n📈 PER-SLICE METRICS (across all samples):\")\n        print(\"-\"*40)\n        for metric_name, values in self.metrics_df.items():\n            print(f\"   {metric_name:20s}: mean={np.mean(values):.4f}, std={np.std(values):.4f}, \"\n                  f\"min={np.min(values):.4f}, max={np.max(values):.4f}\")\n        \n        # Diversity Metrics\n        print(\"\\n🎨 DIVERSITY METRICS:\")\n        print(\"-\"*40)\n        for name, value in self.diversity_metrics.items():\n            status = \"✅\" if value > 0.02 else \"⚠️\"\n            print(f\"   {name:25s}: {value:.4f} {status}\")\n        \n        # Realism Metrics\n        print(\"\\n🔬 REALISM METRICS (vs Real Data):\")\n        print(\"-\"*40)\n        for name, value in self.realism_metrics.items():\n            status = \"✅\" if value > 0.8 else (\"⚠️\" if value > 0.6 else \"❌\")\n            print(f\"   {name:25s}: {value:.4f} {status}\")\n        \n        # Overall Assessment\n        print(\"\\n\" + \"=\"*70)\n        print(\"🎯 OVERALL ASSESSMENT:\")\n        print(\"=\"*70)\n        \n        # Calculate overall score\n        overall_ssim = np.mean(self.metrics_df['ssim'])\n        diversity = self.diversity_metrics['diversity_score']\n        realism = np.mean(list(self.realism_metrics.values()))\n        \n        overall_score = (overall_ssim * 0.4 + diversity * 0.3 + realism * 0.3)\n        \n        print(f\"\\n   SSIM Quality:      {overall_ssim:.4f} (weight: 40%)\")\n        print(f\"   Diversity Score:   {diversity:.4f} (weight: 30%)\")\n        print(f\"   Realism Score:     {realism:.4f} (weight: 30%)\")\n        print(f\"   ─────────────────────────────────\")\n        print(f\"   OVERALL SCORE:     {overall_score:.4f}\")\n        \n        if overall_score >= 0.6:\n            print(\"\\n   🏆 VERDICT: EXCELLENT - Ready for classifier augmentation!\")\n        elif overall_score >= 0.45:\n            print(\"\\n   ✅ VERDICT: GOOD - Suitable for data augmentation\")\n        elif overall_score >= 0.3:\n            print(\"\\n   ⚠️ VERDICT: MODERATE - Use with caution, consider more training\")\n        else:\n            print(\"\\n   ❌ VERDICT: POOR - Needs more training or architecture changes\")\n        \n        # Recommendations\n        print(\"\\n💡 RECOMMENDATIONS:\")\n        print(\"-\"*40)\n        if good_pct < 50:\n            print(\"   • Consider training for more epochs\")\n        if diversity < 0.3:\n            print(\"   • Low diversity - check for mode collapse\")\n        if overall_ssim < 0.4:\n            print(\"   • Low SSIM - architecture or LR adjustment may help\")\n        if self.realism_metrics['histogram_intersection'] < 0.7:\n            print(\"   • Intensity distribution doesn't match real data well\")\n        if good_pct >= 50 and diversity >= 0.3:\n            print(\"   • ✅ Quality is good - proceed with augmentation!\")\n        \n        print(\"\\n\" + \"=\"*70)\n        \n        return {\n            'quality_counts': self.quality_counts,\n            'good_percentage': good_pct,\n            'usable_percentage': usable_pct,\n            'overall_score': overall_score,\n            'metrics_summary': {k: np.mean(v) for k, v in self.metrics_df.items()},\n            'diversity': self.diversity_metrics,\n            'realism': self.realism_metrics\n        }\n    \n    def plot_quality_analysis(self):\n        \"\"\"Generate visualization plots\"\"\"\n        fig, axes = plt.subplots(2, 3, figsize=(15, 10))\n        \n        # 1. Quality Distribution Pie Chart\n        ax = axes[0, 0]\n        colors = {'GOOD': '#2ecc71', 'MEDIUM': '#f39c12', 'POOR': '#e74c3c'}\n        ax.pie([self.quality_counts['GOOD'], self.quality_counts['MEDIUM'], self.quality_counts['POOR']],\n               labels=['Good', 'Medium', 'Poor'],\n               colors=[colors['GOOD'], colors['MEDIUM'], colors['POOR']],\n               autopct='%1.1f%%', startangle=90)\n        ax.set_title('Quality Distribution')\n        \n        # 2. SSIM Histogram\n        ax = axes[0, 1]\n        ax.hist(self.metrics_df['ssim'], bins=30, color='steelblue', edgecolor='black', alpha=0.7)\n        ax.axvline(0.5, color='green', linestyle='--', label='Good threshold')\n        ax.axvline(0.35, color='orange', linestyle='--', label='Medium threshold')\n        ax.set_xlabel('SSIM Score')\n        ax.set_ylabel('Count')\n        ax.set_title('SSIM Distribution')\n        ax.legend()\n        \n        # 3. Brain Ratio Histogram\n        ax = axes[0, 2]\n        ax.hist(self.metrics_df['brain_ratio'], bins=30, color='coral', edgecolor='black', alpha=0.7)\n        ax.axvline(0.15, color='green', linestyle='--', label='Good threshold')\n        ax.set_xlabel('Brain Content Ratio')\n        ax.set_ylabel('Count')\n        ax.set_title('Brain Content Distribution')\n        ax.legend()\n        \n        # 4. SSIM vs Brain Ratio Scatter\n        ax = axes[1, 0]\n        colors_scatter = [colors[q] for q in self.quality_labels]\n        ax.scatter(self.metrics_df['ssim'], self.metrics_df['brain_ratio'], \n                   c=colors_scatter, alpha=0.5, s=10)\n        ax.set_xlabel('SSIM')\n        ax.set_ylabel('Brain Ratio')\n        ax.set_title('Quality Scatter Plot')\n        ax.axhline(0.15, color='gray', linestyle='--', alpha=0.5)\n        ax.axvline(0.5, color='gray', linestyle='--', alpha=0.5)\n        \n        # 5. Intensity Distribution Comparison\n        ax = axes[1, 1]\n        ax.hist(self.fake_images.flatten(), bins=50, alpha=0.5, label='Fake', density=True)\n        ax.hist(self.real_images.flatten(), bins=50, alpha=0.5, label='Real', density=True)\n        ax.set_xlabel('Pixel Intensity')\n        ax.set_ylabel('Density')\n        ax.set_title('Intensity Distribution: Fake vs Real')\n        ax.legend()\n        \n        # 6. Sample Good/Medium/Poor images\n        ax = axes[1, 2]\n        # Find one example of each quality\n        good_idx = self.quality_labels.index('GOOD') if 'GOOD' in self.quality_labels else 0\n        med_idx = self.quality_labels.index('MEDIUM') if 'MEDIUM' in self.quality_labels else 0\n        poor_idx = self.quality_labels.index('POOR') if 'POOR' in self.quality_labels else 0\n        \n        # Create composite image\n        composite = np.hstack([\n            self.fake_images[good_idx, 0],\n            self.fake_images[med_idx, 0],\n            self.fake_images[poor_idx, 0]\n        ])\n        ax.imshow(composite, cmap='gray')\n        ax.set_title('Sample: Good | Medium | Poor')\n        ax.axis('off')\n        \n        plt.tight_layout()\n        plt.savefig(os.path.join(config.OUTPUT_DIR, 'quality_analysis.png'), dpi=150)\n        plt.show()\n        \n        print(f\"\\n📊 Quality analysis plot saved to {config.OUTPUT_DIR}/quality_analysis.png\")\n\n\n# =============================================================================\n# RUN COMPREHENSIVE EVALUATION\n# =============================================================================\n\nprint(\"🔬 Running Comprehensive GAN Evaluation...\")\nprint(\"   This may take a few minutes for 500 samples...\")\n\n# Create evaluator\nevaluator = ComprehensiveEvaluator(\n    generator=trainer.generator,\n    dataloader=dataloader,\n    config=config,\n    device=config.DEVICE,\n    n_samples=500  # Evaluate 500 samples for good statistics\n)\n\n# Apply EMA weights for best quality\nif trainer.ema:\n    trainer.ema.apply_shadow()\n\n# Run all evaluations\nevaluator.generate_samples()\nevaluator.compute_per_slice_metrics()\nevaluator.classify_quality()\nevaluator.compute_diversity_metrics()\nevaluator.compute_realism_metrics()\n\n# Print comprehensive report\nfinal_report = evaluator.print_report()\n\n# Generate plots\nevaluator.plot_quality_analysis()\n\n# Restore weights\nif trainer.ema:\n    trainer.ema.restore()\n\n# Cleanup\ngc.collect()\ntorch.cuda.empty_cache()\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T16:31:36.755949Z\",\"iopub.execute_input\":\"2025-12-10T16:31:36.756383Z\",\"iopub.status.idle\":\"2025-12-10T16:32:17.872671Z\",\"shell.execute_reply.started\":\"2025-12-10T16:31:36.756360Z\",\"shell.execute_reply\":\"2025-12-10T16:32:17.871926Z\"}}\n# =============================================================================\n# 🎯 GENERATE ONLY HIGH-QUALITY IMAGES\n# =============================================================================\n# This cell generates images and only saves the ones that pass quality checks\n\nfrom PIL import Image\nimport json\n\ndef generate_quality_filtered_dataset(\n    generator, \n    config, \n    device,\n    target_count=10000,\n    min_ssim=0.45,\n    min_brain_ratio=0.12,\n    output_dir=None,\n    ema=None\n):\n    \"\"\"\n    Generate synthetic images with quality filtering.\n    Only saves images that pass quality thresholds.\n    \n    Args:\n        generator: Trained generator model\n        config: Configuration object\n        device: torch device\n        target_count: Number of GOOD images to generate\n        min_ssim: Minimum SSIM score to pass\n        min_brain_ratio: Minimum brain content ratio\n        output_dir: Where to save images\n        ema: EMA object (optional)\n    \n    Returns:\n        stats: Dictionary with generation statistics\n    \"\"\"\n    \n    if output_dir is None:\n        output_dir = os.path.join(config.OUTPUT_DIR, 'filtered_synthetic_images')\n    os.makedirs(output_dir, exist_ok=True)\n    \n    # Get some real images for SSIM comparison\n    real_samples = []\n    for batch in dataloader:\n        real = batch.to(device)\n        real = (real + 1) / 2.0\n        real_samples.append(real.cpu().numpy())\n        if sum(len(r) for r in real_samples) >= 100:\n            break\n    real_pool = np.concatenate(real_samples, axis=0)[:100]\n    \n    # Apply EMA if available\n    if ema:\n        ema.apply_shadow()\n    \n    generator.eval()\n    \n    # Statistics\n    stats = {\n        'total_generated': 0,\n        'good_count': 0,\n        'medium_count': 0,\n        'rejected_count': 0,\n        'ssim_scores': [],\n        'brain_ratios': [],\n        'saved_indices': []\n    }\n    \n    batch_size = 32\n    saved_count = 0\n    attempts = 0\n    max_attempts = target_count * 5  # Generate up to 5x to find enough good ones\n    \n    print(f\"🎯 Generating {target_count:,} high-quality images...\")\n    print(f\"   Quality thresholds: SSIM >= {min_ssim}, Brain Ratio >= {min_brain_ratio}\")\n    print(f\"   Output: {output_dir}\")\n    print()\n    \n    pbar = tqdm(total=target_count, desc=\"Saving quality images\")\n    \n    with torch.no_grad():\n        while saved_count < target_count and attempts < max_attempts:\n            # Generate batch\n            z = torch.randn(batch_size, config.LATENT_DIM).to(device)\n            fake = generator(z)\n            fake = (fake + 1) / 2.0\n            fake = torch.clamp(fake, 0, 1)\n            fake_np = fake.cpu().numpy()\n            \n            # Evaluate each image\n            for i in range(len(fake_np)):\n                if saved_count >= target_count:\n                    break\n                    \n                attempts += 1\n                stats['total_generated'] += 1\n                \n                img = fake_np[i, 0]\n                \n                # Quality checks\n                brain_ratio = np.sum(img > 0.05) / img.size\n                \n                # Compare to random real image\n                real_idx = np.random.randint(len(real_pool))\n                real_img = real_pool[real_idx, 0]\n                ssim_score = ssim(img, real_img, data_range=1.0)\n                \n                stats['ssim_scores'].append(ssim_score)\n                stats['brain_ratios'].append(brain_ratio)\n                \n                # Classify\n                if ssim_score >= min_ssim and brain_ratio >= min_brain_ratio:\n                    # GOOD - save it\n                    quality = 'good'\n                    stats['good_count'] += 1\n                    \n                    # Save image\n                    img_uint8 = (img * 255).astype(np.uint8)\n                    Image.fromarray(img_uint8, mode='L').save(\n                        os.path.join(output_dir, f'ftd_synthetic_{saved_count:06d}.png')\n                    )\n                    stats['saved_indices'].append(saved_count)\n                    saved_count += 1\n                    pbar.update(1)\n                    \n                elif ssim_score >= 0.35 and brain_ratio >= 0.10:\n                    # MEDIUM - optionally save\n                    stats['medium_count'] += 1\n                    # Could add option to save medium quality too\n                else:\n                    # POOR - reject\n                    stats['rejected_count'] += 1\n            \n            # Periodic cleanup\n            if attempts % 1000 == 0:\n                gc.collect()\n                torch.cuda.empty_cache()\n    \n    pbar.close()\n    \n    # Restore EMA\n    if ema:\n        ema.restore()\n    \n    generator.train()\n    \n    # Calculate final stats\n    stats['acceptance_rate'] = stats['good_count'] / stats['total_generated'] * 100\n    stats['avg_ssim'] = np.mean(stats['ssim_scores'])\n    stats['avg_brain_ratio'] = np.mean(stats['brain_ratios'])\n    \n    # Save metadata\n    metadata = {\n        'target_count': target_count,\n        'actual_saved': saved_count,\n        'total_generated': stats['total_generated'],\n        'acceptance_rate': stats['acceptance_rate'],\n        'quality_thresholds': {\n            'min_ssim': min_ssim,\n            'min_brain_ratio': min_brain_ratio\n        },\n        'avg_ssim': stats['avg_ssim'],\n        'avg_brain_ratio': stats['avg_brain_ratio']\n    }\n    \n    with open(os.path.join(output_dir, 'generation_metadata.json'), 'w') as f:\n        json.dump(metadata, f, indent=2)\n    \n    # Print summary\n    print(\"\\n\" + \"=\"*60)\n    print(\"📊 QUALITY-FILTERED GENERATION COMPLETE\")\n    print(\"=\"*60)\n    print(f\"   Total Generated:  {stats['total_generated']:,}\")\n    print(f\"   Good Quality:     {stats['good_count']:,} (saved)\")\n    print(f\"   Medium Quality:   {stats['medium_count']:,} (not saved)\")\n    print(f\"   Rejected:         {stats['rejected_count']:,}\")\n    print(f\"   Acceptance Rate:  {stats['acceptance_rate']:.1f}%\")\n    print(f\"   Average SSIM:     {stats['avg_ssim']:.4f}\")\n    print(f\"   Average Brain:    {stats['avg_brain_ratio']:.4f}\")\n    print(f\"   Output Location:  {output_dir}\")\n    print(\"=\"*60)\n    \n    return stats\n\n\n# =============================================================================\n# RUN QUALITY-FILTERED GENERATION\n# =============================================================================\n\nprint(\"🎯 Starting quality-filtered image generation...\")\nprint(\"   Only images that pass quality checks will be saved.\\n\")\n\n# Generate high-quality images only\nquality_stats = generate_quality_filtered_dataset(\n    generator=trainer.generator,\n    config=config,\n    device=config.DEVICE,\n    target_count=10000,    # Generate 10,000 good quality images\n    min_ssim=0.45,         # Minimum SSIM threshold\n    min_brain_ratio=0.12,  # Minimum brain content\n    output_dir=os.path.join(config.OUTPUT_DIR, 'high_quality_synthetic'),\n    ema=trainer.ema\n)\n\nprint(\"\\n✅ Quality-filtered dataset ready for classifier augmentation!\")\n\n\n# %% [code]\n\n\n# %% [code]\n\n\n# %% [code]\n\n\n# %% [code]\n\n\n# %% [code]\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T15:30:28.644343Z\",\"iopub.execute_input\":\"2025-12-10T15:30:28.644624Z\",\"iopub.status.idle\":\"2025-12-10T15:32:33.523415Z\",\"shell.execute_reply.started\":\"2025-12-10T15:30:28.644605Z\",\"shell.execute_reply\":\"2025-12-10T15:32:33.522712Z\"}}\n# =============================================================================\n# 📊 GENERATE SYNTHETIC DATASET\n# =============================================================================\n\nif len(nifti_paths) > 0:\n    print(\"\\n\" + \"=\" * 70)\n    print(\"📊 Generating Synthetic Dataset...\")\n    print(\"=\" * 70)\n    \n    output_dir = os.path.join(config.OUTPUT_DIR, 'synthetic_ftd_images')\n    trainer.generate_synthetic_dataset(\n        num_samples=config.SYNTHETIC_TO_GENERATE,\n        output_dir=output_dir\n    )\n    \n    # Count generated files\n    generated_files = glob.glob(os.path.join(output_dir, '*.png'))\n    print(f\"\\n✅ Generated {len(generated_files):,} images in {output_dir}\")\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T15:32:33.524326Z\",\"iopub.execute_input\":\"2025-12-10T15:32:33.524610Z\",\"iopub.status.idle\":\"2025-12-10T15:32:34.358173Z\",\"shell.execute_reply.started\":\"2025-12-10T15:32:33.524587Z\",\"shell.execute_reply\":\"2025-12-10T15:32:34.357346Z\"}}\n# =============================================================================\n# 🎨 VISUALIZE GENERATED SAMPLES\n# =============================================================================\n\nif len(nifti_paths) > 0:\n    from PIL import Image\n    \n    output_dir = os.path.join(config.OUTPUT_DIR, 'synthetic_ftd_images')\n    sample_files = sorted(glob.glob(os.path.join(output_dir, '*.png')))[:16]\n    \n    if sample_files:\n        fig, axes = plt.subplots(4, 4, figsize=(12, 12))\n        for i, (ax, f) in enumerate(zip(axes.flat, sample_files)):\n            img = Image.open(f)\n            ax.imshow(img, cmap='gray')\n            ax.axis('off')\n        plt.suptitle('Generated Synthetic FTD MRI Slices', fontsize=14)\n        plt.tight_layout()\n        plt.show()\n\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2025-12-10T15:32:34.359047Z\",\"iopub.execute_input\":\"2025-12-10T15:32:34.359241Z\",\"iopub.status.idle\":\"2025-12-10T15:32:42.544284Z\",\"shell.execute_reply.started\":\"2025-12-10T15:32:34.359226Z\",\"shell.execute_reply\":\"2025-12-10T15:32:42.543614Z\"}}\n# =============================================================================\n# 📦 ZIP OUTPUTS FOR DOWNLOAD\n# =============================================================================\n\nprint(\"📦 Creating downloadable archives...\")\n\n# Zip synthetic images\nsynthetic_dir = os.path.join(config.OUTPUT_DIR, 'synthetic_ftd_images')\nif os.path.exists(synthetic_dir):\n    zip_path = '/kaggle/working/synthetic_ftd_images.zip'\n    \n    # Use shell command for speed\n    import subprocess\n    result = subprocess.run(\n        f'cd {synthetic_dir} && zip -q -r {zip_path} .',\n        shell=True, capture_output=True\n    )\n    \n    if os.path.exists(zip_path):\n        size_mb = os.path.getsize(zip_path) / (1024*1024)\n        print(f\"   ✅ synthetic_ftd_images.zip: {size_mb:.1f} MB\")\n\n# List outputs\nprint(\"\\n📂 Output files in /kaggle/working/:\")\nfor item in os.listdir('/kaggle/working'):\n    path = os.path.join('/kaggle/working', item)\n    if os.path.isfile(path):\n        size = os.path.getsize(path) / (1024*1024)\n        print(f\"   {item}: {size:.1f} MB\")\n    else:\n        print(f\"   {item}/ (directory)\")\n\nprint(\"\\n🎉 Done! Download your files from the Output tab (right sidebar)\")\n\n\n# %% [markdown]\n# ---\n# \n# ## 📝 Training Summary\n# \n# ### Current Configuration:\n# - **40 epochs** total\n# - **Checkpoints saved** at epoch 20 and 40\n# - **Evaluation metrics** computed at epoch 20 and 40\n# - **Sample images** generated at epoch 20 and 40\n# \n# ### If You Need to Resume:\n# 1. Download checkpoint from `/kaggle/working/checkpoints/`\n# 2. Upload it as a new Kaggle Dataset\n# 3. Set `RESUME_FROM_CHECKPOINT = True` in the Resume cell\n# 4. Update `CHECKPOINT_PATH` to your uploaded checkpoint\n# 5. Run again!\n# \n# ### Memory Safety Features:\n# - ✅ Batch size: 24 (stable for 16GB RAM)\n# - ✅ Max samples: 10,000 (prevents OOM during loading)\n# - ✅ Eval samples: 32 (minimal memory during evaluation)\n# - ✅ GC every 25 batches + after each epoch\n# - ✅ Loss history limited to 500 entries\n# - ✅ `num_workers=0` (no multiprocessing memory leaks)\n# \n# ### If OOM Occurs:\n# - Reduce `BATCH_SIZE` to 16\n# - Reduce `MAX_SAMPLES` to 8000\n# - The code will auto-save checkpoint on OOM\n# \n# ---\n# \n# **Created for DementiaNext Project**\n# ","metadata":{"_uuid":"bcf66032-44dd-4951-b0e6-44a54830300b","_cell_guid":"4d6c10f9-590a-473d-842b-0212ae2572cc","trusted":true,"collapsed":false,"jupyter":{"outputs_hidden":false}},"outputs":[],"execution_count":null}]}